import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import {
  addCommentToTask,
  assignTaskToUser,
  createTask,
  deleteTask,
  getTasksByProject,
  updateTask,
  updateTaskStatus,
  uploadTaskFile,
} from "../services/taskService";

function TaskPage() {
  const { id } = useParams(); // 🔥 projectId

  const [tasks, setTasks] = useState([]);
  const [editingTaskId, setEditingTaskId] = useState(null);
  const [commentInputs, setCommentInputs] = useState({});
  const [selectedFiles, setSelectedFiles] = useState({});

  const [formData, setFormData] = useState({
    title: "",
    description: "",
    priority: "medium",
    deadline: "",
    projectId: id,
  });

  // 🔹 Fetch tasks
  const fetchTasks = async () => {
    try {
      const data = await getTasksByProject(id);
      setTasks(data);
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    if (id) fetchTasks();
  }, [id]);

  // 🔹 Form
  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  // 🔹 Create / Update
  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      if (editingTaskId) {
        await updateTask(editingTaskId, formData);
      } else {
        await createTask({ ...formData, projectId: id });
      }

      setFormData({
        title: "",
        description: "",
        priority: "medium",
        deadline: "",
        projectId: id,
      });

      setEditingTaskId(null);
      fetchTasks();
    } catch (err) {
      console.error(err);
    }
  };

  // 🔹 Delete
  const handleDelete = async (taskId) => {
    await deleteTask(taskId);
    fetchTasks();
  };

  // 🔹 Status
  const handleStatusChange = async (taskId, status) => {
    await updateTaskStatus(taskId, status);

    setTasks((prev) =>
      prev.map((t) =>
        t._id === taskId ? { ...t, status } : t
      )
    );
  };

  // 🔹 Assign
  const handleAssignChange = async (taskId, userId) => {
    await assignTaskToUser(taskId, userId);
    fetchTasks();
  };

  // 🔹 Edit
  const handleEdit = (task) => {
    setEditingTaskId(task._id);
    setFormData({
      title: task.title,
      description: task.description,
      priority: task.priority,
      deadline: task.deadline?.slice(0, 10),
      projectId: id,
    });
  };

  // 🔹 Comments
  const handleAddComment = async (taskId) => {
    const text = commentInputs[taskId];
    if (!text) return;

    await addCommentToTask(taskId, { text });
    setCommentInputs({ ...commentInputs, [taskId]: "" });
    fetchTasks();
  };

  // 🔹 Files
  const handleFileUpload = async (taskId) => {
    const file = selectedFiles[taskId];
    if (!file) return;

    await uploadTaskFile(taskId, file);
    fetchTasks();
  };

  return (
    <div style={{ padding: "20px" }}>
      <h1>Tasks - Project</h1>

      {/* FORM */}
      <form onSubmit={handleSubmit}>
        <input
          name="title"
          value={formData.title}
          onChange={handleChange}
          placeholder="Title"
          required
        />

        <textarea
          name="description"
          value={formData.description}
          onChange={handleChange}
        />

        <select
          name="priority"
          value={formData.priority}
          onChange={handleChange}
        >
          <option value="low">Low</option>
          <option value="medium">Medium</option>
          <option value="high">High</option>
        </select>

        <input
          type="date"
          name="deadline"
          value={formData.deadline}
          onChange={handleChange}
        />

        <button type="submit">
          {editingTaskId ? "Update" : "Create Task"}
        </button>
      </form>

      {/* TASK LIST */}
      {tasks.map((task) => (
        <div key={task._id} style={{ border: "1px solid #ccc", marginTop: "10px", padding: "10px" }}>
          <h3>{task.title}</h3>
          <p>{task.description}</p>

          <p>Status: {task.status}</p>

          {/* STATUS */}
          <select
            value={task.status}
            onChange={(e) =>
              handleStatusChange(task._id, e.target.value)
            }
          >
            <option value="todo">To do</option>
            <option value="inprogress">In progress</option>
            <option value="done">Done</option>
          </select>

          {/* ASSIGN */}
          <select
            value={task.assignedTo || ""}
            onChange={(e) =>
              handleAssignChange(task._id, e.target.value)
            }
          >
            <option value="">Assign user</option>
            <option value="USER_ID_1">User 1</option>
            <option value="USER_ID_2">User 2</option>
          </select>

          <br />

          {/* ACTIONS */}
          <button onClick={() => handleEdit(task)}>Edit</button>
          <button onClick={() => handleDelete(task._id)}>Delete</button>

          {/* COMMENTS */}
          <div>
            <h4>Comments</h4>
            {task.comments?.map((c) => (
              <p key={c._id}>{c.text}</p>
            ))}

            <input
              value={commentInputs[task._id] || ""}
              onChange={(e) =>
                setCommentInputs({
                  ...commentInputs,
                  [task._id]: e.target.value,
                })
              }
            />
            <button onClick={() => handleAddComment(task._id)}>
              Add
            </button>
          </div>

          {/* FILE */}
          <div>
            <input
              type="file"
              onChange={(e) =>
                setSelectedFiles({
                  ...selectedFiles,
                  [task._id]: e.target.files[0],
                })
              }
            />
            <button onClick={() => handleFileUpload(task._id)}>
              Upload
            </button>
          </div>
        </div>
      ))}
    </div>
  );
}

export default TaskPage;
